import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Limit user input length to prevent buffer overflow
        byte[] buffer = new byte[10];
        int length = Math.min(userInput.length(), buffer.length);

        // Copy only up to 'length' bytes from user input to the buffer
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, length);

        System.out.println("User input stored in buffer: " + new String(Arrays.copyOf(buffer, length)));
    }
}

